    const taskDescription = taskDescriptionInput.value;

    if (taskTitle && taskDescription) {
        const newTask = {
            title: taskTitle,
            description: taskDescription,
            completed: false
        };

        tasks.push(newTask);
        saveTasksToLocalStorage();
        renderTaskList();
        taskTitleInput.value = '';
        taskDescriptionInput.value = '';
    }
}

// Save tasks to local storage function
function saveTasksToLocalStorage() {
    localStorage.setItem('tasks', JSON.stringify(tasks));
}

// Render task list function
function renderTaskList() {
    taskList.innerHTML = '';
    tasks.forEach((task, index) => {
        const taskHtml = `
            <li class="task ${task.completed ? 'completed' : ''}">
                <input type="checkbox" ${task.completed ? 'checked' : ''} data-index="${index}">
                <span>${task.title}</span>
                <span>${task.description}</span>
                <button class="update-task-btn" data-index="${index}">Update</button>
                <button class="delete-task-btn" data-index="${index}">Delete</button>
            </li>
        `;
        taskList.insertAdjacentHTML('beforeend', taskHtml);
    });
}

// Update task function
function updateTask(index) {
    const updatedTask = tasks[index];
    const newTitle = prompt('Enter new title:', updatedTask.title);
    const newDescription = prompt('Enter new description:', updatedTask.description);

    if (newTitle && newDescription) {
        updatedTask.title = newTitle;
        updatedTask.description = newDescription;
        saveTasksToLocalStorage();
        renderTaskList();
    }
}

// Delete task function
function deleteTask(index) {
    tasks.splice(index, 1);
    saveTasksToLocalStorage();
    renderTaskList();
}

// Event listeners
createTaskBtn.addEventListener('click', createTask);

taskList.addEventListener('change', (e) => {
    if (e.target.type === 'checkbox') {
        const index = e.target.dataset.index;
        tasks[index].completed = e.target.checked;
        saveTasksToLocalStorage();
        renderTaskList();
    }
});

taskList.addEventListener('click', (e) => {
    if (e.target.classList.contains('update-task-btn')) {
        const index = e.target.dataset.index;
        updateTask(index);
    } else if (e.target.classList.contains('delete-task-btn')) {
        const index = e.target.dataset.index;
        deleteTask(index);
    }
});
