// app.js
import React, { useState, useEffect } from 'react';
import { add, subtract, multiply, divide } from './calculator-engine';

function Calculator() {
  const [num1, setNum1] = useState(0);
  const [num2, setNum2] = useState(0);
  const [result, setResult] = useState(0);
  const [operation, setOperation] = useState('+');

  useEffect(() => {
    const calculate = () => {
      switch (operation) {
        case '+':
          setResult(add(num1, num2));
          break;
        case '-':
          setResult(subtract(num1, num2));
          break;
        case '*':
          setResult(multiply(num1, num2));
          break;
        case '/':
          setResult(divide(num1, num2));
          break;
        default:
          throw new Error('Invalid operation');
      }
    };
    calculate();
  }, [num1, num2, operation]);

  const handleInputChange = (event) => {
    const { name, value } = event.target;
    if (name === 'num1') {
      setNum1(parseFloat(value));
    } else if (name === 'num2') {
      setNum2(parseFloat(value));
    }
  };

  const handleOperationChange = (event) => {
    setOperation(event.target.value);
  };

  return (
    <div>
      <input type="number" name="num1" value={num1} onChange={handleInputChange} />
      <select value={operation} onChange={handleOperationChange}>
        <option value="+">+</option>
        <option value="-">-</option>
        <option value="*">*</option>
        <option value="/">/</option>
      </select>
      <input type="number" name="num2" value={num2} onChange={handleInputChange} />
      <p>Result: {result}</p>
    </div>
  );
}

export default Calculator;
```
